module top_module(
    A,
    B,
    C,
    D,
    not_sel,
    Y
);// Module ports
    input  A;
    input  B;
    input  C;
    input  D;
    input  [1:0] not_sel;
    output Y;

    // Assign output Y based on the select signal
    assign Y = (not_sel == 2'b00) ? A : 
               (not_sel == 2'b01) ? B : 
               (not_sel == 2'b10) ? C : 
                                D;

endmodule
